import { IMessageComposer } from '@nitrots/nitro-renderer';

export class AcceptPoliceCallComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(
        username: string,
        virtualRoomId: number,
        virtualRoomName: string
    ) {
        this._data = [username, virtualRoomId, virtualRoomName];
        console.log('[📤] AcceptPoliceCallComposer packet sent:', this._data);
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
